const PARAMS = { target_temp:37, initial_temp:20, hot_water_temp:60, cold_water_temp:10, max_flow_rate:1, max_dump_flow_rate:1, mixed_water_cooling_rate:0.01, dt:0.1, max_steps:600, tank_capacity:1, ambient_temp:20, temp_min:0, temp_max:100 };
const clamp = (x,lo,hi) => Math.max(lo, Math.min(hi, x));
if (msg.payload && msg.payload.reset) {
  const volRatio = Math.random() * 0.95;
  flow.set('hot_supply_temp', PARAMS.hot_water_temp);
  flow.set('cold_supply_temp', PARAMS.cold_water_temp);
  flow.set('hot_flow', 0); flow.set('cold_flow', 0); flow.set('dump_flow', 0);
  flow.set('volume', Math.max(0.01, PARAMS.tank_capacity * volRatio));
  flow.set('current_temp', PARAMS.initial_temp);
  flow.set('step_count', 0);
  const obs = [PARAMS.cold_water_temp/100, PARAMS.hot_water_temp/100, PARAMS.initial_temp/100, flow.get('volume')/PARAMS.tank_capacity];
  msg.payload = { observation: obs, observation_names: ["thermometer_cold","thermometer_hot","thermometer_tank","water_level"], action_names: ["cold_valve","dump_valve","hot_valve"], reward: 0, done: false };
  msg.headers = { 'Content-Type': 'application/json' };
  return [msg, null];
}
flow.set('action', msg.payload.action || [0,0,0]);
flow.set('http_msg', msg);
flow.set('agent_sent_this_step', false);
return [null, msg];

const clamp = (x,lo,hi) => Math.max(lo, Math.min(hi, x));
let t = flow.get('hot_supply_temp');
if (t == null) t = 60;
let drift = typeof msg.payload === 'number' ? msg.payload : (Math.random()-0.5)*0.4;
t = clamp(t + drift, 0, 100);
flow.set('hot_supply_temp', t);
msg.payload = { temp: t }; msg.topic = 'thermometer_hot';
return msg;

const clamp = (x,lo,hi) => Math.max(lo, Math.min(hi, x));
let t = flow.get('cold_supply_temp');
if (t == null) t = 10;
let drift = typeof msg.payload === 'number' ? msg.payload : (Math.random()-0.5)*0.4;
t = clamp(t + drift, 0, 100);
flow.set('cold_supply_temp', t);
msg.payload = { temp: t }; msg.topic = 'thermometer_cold';
return msg;

msg.topic = 'thermometer_hot';
msg.payload = typeof msg.payload === 'object' && msg.payload.temp != null ? msg.payload.temp : msg.payload;
return msg;

msg.topic = 'thermometer_cold';
msg.payload = typeof msg.payload === 'object' && msg.payload.temp != null ? msg.payload.temp : msg.payload;
return msg;

if (flow.get('agent_sent_this_step')) return null;
flow.set('agent_sent_this_step', true);
const cap = 1;
const obs = [
  (flow.get('cold_supply_temp')||10)/100,
  (flow.get('hot_supply_temp')||60)/100,
  (flow.get('current_temp')||20)/100,
  Math.min(1, (flow.get('volume')||0.5)/cap)
];
const action = flow.get('action') || [0,0,0];
return { payload: action };

const clamp = (x,lo,hi) => Math.max(lo, Math.min(hi, x));
const action = Array.isArray(msg.payload) ? msg.payload : (flow.get('action') || [0,0,0]);
let f = flow.get('hot_flow'); if (f == null) f = 0;
f = clamp(f + (action[2] || 0) * 0.6, 0, 1);
flow.set('hot_flow', f);
const temp = flow.get('hot_supply_temp') || 60;
msg.payload = { flow: f, temp, source: 'hot' };
return msg;

const clamp = (x,lo,hi) => Math.max(lo, Math.min(hi, x));
const action = Array.isArray(msg.payload) ? msg.payload : (flow.get('action') || [0,0,0]);
let f = flow.get('cold_flow'); if (f == null) f = 0;
f = clamp(f + (action[0] || 0) * 0.6, 0, 1);
flow.set('cold_flow', f);
const temp = flow.get('cold_supply_temp') || 10;
msg.payload = { flow: f, temp, source: 'cold' };
return msg;

const clamp = (x,lo,hi) => Math.max(lo, Math.min(hi, x));
const action = Array.isArray(msg.payload) ? msg.payload : (flow.get('action') || [0,0,0]);
let f = flow.get('dump_flow'); if (f == null) f = 0;
f = clamp(f + (action[1] || 0) * 0.6, 0, 1);
flow.set('dump_flow', f);
msg.payload = { flow: f, source: 'dump' };
return msg;

const clamp = (x,lo,hi) => Math.max(lo, Math.min(hi, x));
const p = msg.payload;
let inputs = flow.get('tank_inputs') || {};
inputs[p.source] = p;
if (Object.keys(inputs).length < 3) { flow.set('tank_inputs', inputs); return null; }
flow.set('tank_inputs', {});
const hot = inputs.hot || {}; const cold = inputs.cold || {}; const dump = inputs.dump || {};
const dt = 0.1, cooling = 0.01, ambient = 20, cap = 1, tMin = 0, tMax = 100;
let vol = flow.get('volume'); let curTemp = flow.get('current_temp');
if (vol == null) vol = 0.5; if (curTemp == null) curTemp = 20;
const hotF = (hot.flow || 0) * (1 + (Math.random()-0.5)*0.04);
const coldF = (cold.flow || 0) * (1 + (Math.random()-0.5)*0.04);
const dumpF = (dump.flow || 0) * (1 + (Math.random()-0.5)*0.04);
const totIn = hotF + coldF;
const mixT = totIn > 0.001 ? (hotF*(hot.temp||60)+coldF*(cold.temp||10))/totIn : curTemp;
const prevVol = Math.max(vol, 1e-6);
vol = clamp(prevVol - dumpF*dt + totIn*dt, 0.01, cap);
curTemp = (curTemp*Math.max(prevVol-dumpF*dt,0) + mixT*totIn*dt) / vol;
curTemp = clamp(curTemp - cooling*(curTemp - ambient), tMin, tMax);
flow.set('volume', vol); flow.set('current_temp', curTemp);
const step = (flow.get('step_count') || 0) + 1; flow.set('step_count', step);
const target = 37, tempErr = Math.abs(curTemp - target), volRatio = vol/cap;
let reward = -tempErr;
if (volRatio < 0.8) reward -= 0.5*(0.8-volRatio);
if (tempErr < 0.5) reward += 10; else if (tempErr < 1) reward += 5;
if (volRatio >= 0.8 && volRatio <= 0.85) reward += 10; else if (volRatio >= 0.75) reward += 5; else if (volRatio >= 0.7) reward += 2;
if (volRatio > 0.85) reward -= 2*(volRatio-0.85);
if (tempErr < 0.1 && volRatio >= 0.8 && volRatio <= 0.85) reward += 20;
reward -= 0.01*(flow.get('hot_flow')+flow.get('cold_flow')) + 0.1*flow.get('dump_flow');
if (flow.get('dump_flow') < 0.05) reward += 0.3;
const done = (tempErr < 0.1 && volRatio >= 0.8 && volRatio <= 0.85) || step >= 600;
flow.set('reward', reward); flow.set('done', done);
const out = { temp: curTemp, volume: vol, volRatio };
return [{ payload: out, topic: 'thermometer_tank' }, { payload: out, topic: 'water_level' }];

msg.topic = 'thermometer_tank';
msg.payload = (msg.payload && msg.payload.temp != null) ? msg.payload.temp : msg.payload;
return msg;

msg.topic = 'water_level';
msg.payload = (msg.payload && msg.payload.volRatio != null) ? msg.payload.volRatio : ((msg.payload && msg.payload.volume) ? msg.payload.volume : msg.payload);
return msg;

let obs = flow.get('obs') || {};
obs[msg.topic] = typeof msg.payload === 'number' ? msg.payload : (msg.payload && msg.payload.temp != null ? msg.payload.temp : (msg.payload && msg.payload.volRatio != null ? msg.payload.volRatio : 0));
flow.set('obs', obs);
if (!('thermometer_cold' in obs) || !('thermometer_hot' in obs) || !('thermometer_tank' in obs) || !('water_level' in obs)) return null;
flow.set('obs', {});
const clamp = (x,lo,hi) => Math.max(lo, Math.min(hi, x));
const tMax = 100;
const observation = [
  clamp(obs.thermometer_cold/tMax,0,1),
  clamp(obs.thermometer_hot/tMax,0,1),
  clamp(obs.thermometer_tank/tMax,0,1),
  clamp(typeof obs.water_level === 'number' ? obs.water_level : 0.5, 0, 1)
];
const reward = flow.get('reward') || 0;
const done = flow.get('done') || false;
const httpMsg = flow.get('http_msg') || {};
httpMsg.payload = { observation, reward, done };
httpMsg.headers = { 'Content-Type': 'application/json' };
return httpMsg;
